	position: relative;
	display: flex;
	align-items: center;
	gap: calc(2 * var(--default-grid-baseline));
	min-height: var(--nc-form-box-item-min-height);
	padding-inline: var(--form-element-label-padding);
	border: 1px solid var(--color-primary-element-extra-light-hover);
